import React, { useEffect, useState, useCallback } from 'react';
import { CRow, CCol, CCard, CCardHeader, CCardBody } from '@coreui/react';
import { settingsConfigs } from 'src/services/SupperSettings/index';
import GenericTable from 'src/components/Generic.Table';
import MotifsC from './Motifs';
import i18n from 'src/i18n';
import DeleteRow from 'src/components/module.common/delete.row';

const LMotifs = () => {
    const [list, setList] = useState([]);

    const fetchMotifs = useCallback(async () => {
        try {
            const response = await settingsConfigs.getConfig("motifs");
            setList(response?.data || []);
        } catch (error) {
            console.error('Error fetching hardwares list:', error);
        }
    }, []);

    useEffect(() => {
        fetchMotifs();
    }, [fetchMotifs]);

    const columns = [
        { label: i18n.t('nameInputLabel'), field: 'name' },
        {
            label: i18n.t('actionLabel'),
            field: 'actions',
            render: (item) =>
            (
                <>
                    <DeleteRow refresh={() => fetchMotifs()} status={item.status} data={"motifs"} entityName={i18n.t('HardwaresTableTitle')} id={item.id} name={item.name} />
                    <MotifsC refresh={fetchMotifs} selectedMotifs={item} />
                </>
            )
        },
    ];

    return (
        <CCard className="mb-4">
            <CCardHeader>
                <CRow className="align-items-center">
                    <CCol md="6" xs="12">
                        <strong>{i18n.t('MotifsTableTitle')}</strong>
                    </CCol>
                    <CCol md="6" xs="12" className="text-md-end mt-md-0 mt-3">
                        <MotifsC refresh={fetchMotifs} />
                    </CCol>
                </CRow>
            </CCardHeader>
            <CCardBody>
                <GenericTable columns={columns} data={list.filter(item => item.type === 'motif')} />
            </CCardBody>
        </CCard>
    );
};

export default LMotifs;
